// src/index.js - React Entry Point

import React from 'react';
import { createRoot } from 'react-dom/client';
import './index.css';
import App from './App';
import reportWebVitals from './reportWebVitals';

// Error Boundary Component
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    // Update state so the next render will show the fallback UI
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    // Log error details
    console.error('Error Boundary caught an error:', error, errorInfo);
    this.setState({
      error: error,
      errorInfo: errorInfo
    });

    // Send error to monitoring service
    if (process.env.NODE_ENV === 'production') {
      // You can add error reporting service here
      // Example: Sentry, LogRocket, etc.
      this.reportError(error, errorInfo);
    }
  }

  reportError = (error, errorInfo) => {
    // Report error to monitoring service
    try {
      const errorReport = {
        message: error.message,
        stack: error.stack,
        componentStack: errorInfo.componentStack,
        timestamp: new Date().toISOString(),
        userAgent: navigator.userAgent,
        url: window.location.href
      };

      // Send to your error reporting service
      console.log('Error Report:', errorReport);

      // Example: Send to your backend API
      // fetch('/api/errors', {
      //   method: 'POST',
      //   headers: { 'Content-Type': 'application/json' },
      //   body: JSON.stringify(errorReport)
      // });
    } catch (reportingError) {
      console.error('Failed to report error:', reportingError);
    }
  };

  render() {
    if (this.state.hasError) {
      return (
        <div className="error-boundary">
          <div className="error-boundary-content">
            <i className="icon-alert-triangle"></i>
            <h1>Oops! Có lỗi xảy ra</h1>
            <p>
              Ứng dụng đã gặp lỗi không mong muốn. Chúng tôi đã ghi nhận sự cố này 
              và sẽ khắc phục sớm nhất có thể.
            </p>

            {process.env.NODE_ENV === 'development' && (
              <details className="error-details">
                <summary>Chi tiết lỗi (Development)</summary>
                <pre className="error-stack">
                  {this.state.error && this.state.error.toString()}
                  <br />
                  {this.state.errorInfo.componentStack}
                </pre>
              </details>
            )}

            <div className="error-actions">
              <button 
                onClick={() => window.location.reload()}
                className="btn-reload"
              >
                Tải lại trang
              </button>
              <button 
                onClick={() => this.setState({ hasError: false, error: null, errorInfo: null })}
                className="btn-retry"
              >
                Thử lại
              </button>
            </div>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

// Performance monitoring
const sendWebVitals = (metric) => {
  // Send performance metrics to analytics
  if (process.env.NODE_ENV === 'production') {
    console.log('Web Vitals:', metric);

    // Example: Send to Google Analytics
    // gtag('event', metric.name, {
    //   event_category: 'Web Vitals',
    //   event_label: metric.id,
    //   value: Math.round(metric.name === 'CLS' ? metric.value * 1000 : metric.value),
    //   non_interaction: true,
    // });
  }
};

// App initialization
const initializeApp = () => {
  // Set up global error handling
  window.addEventListener('error', (event) => {
    console.error('Global error:', event.error);

    if (process.env.NODE_ENV === 'production') {
      // Report to error monitoring service
      const errorReport = {
        message: event.error?.message || 'Unknown error',
        filename: event.filename,
        lineno: event.lineno,
        colno: event.colno,
        stack: event.error?.stack,
        timestamp: new Date().toISOString(),
        userAgent: navigator.userAgent,
        url: window.location.href
      };

      console.log('Global Error Report:', errorReport);
    }
  });

  // Set up unhandled promise rejection handling
  window.addEventListener('unhandledrejection', (event) => {
    console.error('Unhandled promise rejection:', event.reason);

    if (process.env.NODE_ENV === 'production') {
      const errorReport = {
        type: 'unhandledrejection',
        reason: event.reason?.toString() || 'Unknown rejection',
        stack: event.reason?.stack,
        timestamp: new Date().toISOString(),
        userAgent: navigator.userAgent,
        url: window.location.href
      };

      console.log('Promise Rejection Report:', errorReport);
    }
  });

  // Check for browser compatibility
  const isSupported = () => {
    const requiredFeatures = [
      'Promise',
      'fetch',
      'localStorage',
      'sessionStorage',
      'JSON'
    ];

    return requiredFeatures.every(feature => {
      const isAvailable = feature in window || feature in window.constructor.prototype;
      if (!isAvailable) {
        console.error(`Browser feature not supported: ${feature}`);
      }
      return isAvailable;
    });
  };

  if (!isSupported()) {
    document.body.innerHTML = `
      <div class="browser-compatibility-error">
        <h1>Trình duyệt không được hỗ trợ</h1>
        <p>
          Ứng dụng này yêu cầu trình duyệt hiện đại để hoạt động. 
          Vui lòng cập nhật trình duyệt của bạn hoặc sử dụng:
        </p>
        <ul>
          <li>Chrome 90+</li>
          <li>Firefox 88+</li>
          <li>Safari 14+</li>
          <li>Edge 90+</li>
        </ul>
      </div>
    `;
    return;
  }

  // Set initial theme based on user preference
  const savedTheme = localStorage.getItem('theme');
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
  const initialTheme = savedTheme || (prefersDark ? 'dark' : 'light');

  document.documentElement.setAttribute('data-theme', initialTheme);

  // Listen for theme changes
  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => {
    if (!localStorage.getItem('theme')) {
      document.documentElement.setAttribute('data-theme', e.matches ? 'dark' : 'light');
    }
  });
};

// Initialize app
initializeApp();

// Render app
const container = document.getElementById('root');
const root = createRoot(container);

root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

// Performance monitoring
reportWebVitals(sendWebVitals);

// Service Worker registration (optional)
if ('serviceWorker' in navigator && process.env.NODE_ENV === 'production') {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('/sw.js')
      .then((registration) => {
        console.log('SW registered: ', registration);
      })
      .catch((registrationError) => {
        console.log('SW registration failed: ', registrationError);
      });
  });
}
